 //===----------------------------------------------------------------------===//

 #include "llvm/Transforms/Utils/SimplifyIndVar.h"
+
+// Guard: detect icmp with the "samesign" qualifier; such compares must not be narrowed.
+static inline bool isSameSignICmp(const Instruction *I) {
+  if (auto *IC = dyn_cast<ICmpInst>(I)) return IC->hasSameSign();
+  return false;
+}
