-  auto *URem = BinaryOperator::Create(BinaryOperator::URem, N, D,
-                                      Rem->getName() + ".urem", Rem->getIterator());
-  Rem->replaceAllUsesWith(URem);
-  URem->setDebugLoc(Rem->getDebugLoc());
